The performance score is calculated by considering the following factors with their respective weights:
- Total sales with a 10% bonus if the number of unique customers exceeds 5;
- Average stay length with a 5% bonus if the booking count is more than 10 and the average rating is above 4;
- Total loyalty points with a 20% bonus if the points exceed 500;
- Average discount with a 20% bonus if the offer count is more than 5;
- Average rating with a 20% bonus if the review count is more than 20.

sql:
SELECT title, price
FROM hotel_lists
WHERE price = (SELECT MIN(price) FROM hotel_lists);

SELECT title, rating
FROM hotel_lists
ORDER BY rating DESC;

SELECT title
FROM hotel_lists
WHERE list_id = 0;

SELECT title, price, record_count, rating
FROM hotel_lists
WHERE last_updated LIKE '2023-%';

SELECT hotel_chain, AVG(rating) AS average_rating
FROM hotel_lists
GROUP BY hotel_chain;

SELECT title, price, rating
FROM hotel_lists
ORDER BY rating DESC;

SELECT title, rating AS average_rating
FROM hotel_lists
WHERE rating > 3.5;

SELECT title, rating
FROM hotel_lists
WHERE rating = (SELECT MAX(rating) FROM hotel_lists);

SELECT title, price, record_count, rating AS average_rating
FROM hotel_lists
WHERE hotel_chain = 'Marriott';
